// Procesar CPI USA desde FRED — CPIAUCSL (Consumer Price Index All Urban)
// Formato CSV: DATE,CPIAUCSL\n2026-04-01,332.407\n...
const csv = items[0].json.data || items[0].json.body || '';

if (!csv || typeof csv !== 'string') {
  return [{ json: { error: 'Sin datos CPI', timestamp: new Date().toISOString() } }];
}

const lines = csv.trim().split('\n').filter(l => l && !l.startsWith('DATE'));

// Últimas 3 observaciones mensuales
const recientes = lines.slice(-3).map(line => {
  const [fecha, valor] = line.split(',');
  return {
    fecha: fecha?.trim(),
    cpi: parseFloat(valor?.trim() || 0)
  };
});

const ultimo = recientes[recientes.length - 1];
const anterior = recientes[recientes.length - 2];

const cambio_mensual = ultimo && anterior && anterior.cpi
  ? (((ultimo.cpi - anterior.cpi) / anterior.cpi) * 100).toFixed(3)
  : null;

const resultado = {
  agente: 'MSK BROKER',
  fuente: 'FRED — CPIAUCSL (Federal Reserve St. Louis)',
  indicador: 'CPI USA — All Urban Consumers (1982-84=100)',
  ultima_fecha: ultimo?.fecha,
  cpi_actual: ultimo?.cpi,
  cambio_mensual_pct: cambio_mensual,
  tendencia: parseFloat(cambio_mensual) > 0 ? '⬆️ Inflación subiendo' : '⬇️ Inflación bajando',
  impacto_combustible: Math.abs(parseFloat(cambio_mensual || 0)) > 0.5 ? '⚠️ Presión al alza en costos MSK' : '✅ Estable',
  historico_3m: recientes,
  timestamp: new Date().toISOString()
};

console.log('[MSK]', JSON.stringify(resultado, null, 2));
return [{ json: resultado }];
